package com.naenae.teacher.mypage.service;
import com.naenae.common.file.*;import com.naenae.common.user.domain.User;import com.naenae.common.user.repository.UserRepository;import com.naenae.teacher.mypage.model.*;import java.nio.file.Path;import java.util.Set;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.transaction.support.*;import org.springframework.web.multipart.MultipartFile;
@Service public class TeacherMyPageService {private static final long MAX=5L*1024*1024;private static final Set<String>TYPES=Set.of("image/jpeg","image/png","image/webp");private final UserRepository users;private final LocalFileStorage storage;private final Path root;public TeacherMyPageService(UserRepository users,LocalFileStorage storage,@Value("${app.storage.profile-dir}")String dir){this.users=users;this.storage=storage;this.root=Path.of(dir).toAbsolutePath().normalize();}@Transactional(readOnly=true)public MyPageData get(Long id){User u=user(id);return new MyPageData(u.getName(),u.getEmail(),nickname(u),u.getProfileImageStoredName()!=null);}@Transactional public void update(Long id,String nickname,MultipartFile image){User u=user(id);String value=nickname==null?"":nickname.trim();if(value.isEmpty()||value.length()>100)throw new IllegalArgumentException("닉네임은 1자 이상 100자 이하로 입력해 주세요.");String old=u.getProfileImageStoredName(),next=old;if(image!=null&&!image.isEmpty()){if(image.getSize()>MAX)throw new IllegalArgumentException("프로필 사진은 5MB 이하여야 합니다.");if(!TYPES.contains(image.getContentType()))throw new IllegalArgumentException("JPG, PNG, WEBP 이미지만 등록할 수 있습니다.");StoredFile f=storage.store(root,image);next=f.storedName();}u.updateProfile(value,next);if(old!=null&&!old.equals(next))deleteAfterCommit(old);}@Transactional(readOnly=true)public ProfileImage image(Long id){User u=user(id);if(u.getProfileImageStoredName()==null)throw new IllegalArgumentException("프로필 사진이 없습니다.");return new ProfileImage(storage.resolveExisting(root,u.getProfileImageStoredName()),contentType(u.getProfileImageStoredName()));}private User user(Long id){return users.findById(id).orElseThrow(()->new IllegalStateException("사용자 정보를 찾을 수 없습니다."));}private String nickname(User u){return u.getNickname()==null||u.getNickname().isBlank()?u.getName():u.getNickname();}private String contentType(String n){String v=n.toLowerCase();if(v.endsWith(".png"))return"image/png";if(v.endsWith(".webp"))return"image/webp";return"image/jpeg";}private void deleteAfterCommit(String n){Runnable r=()->storage.deleteIfExists(root,n);if(!TransactionSynchronizationManager.isSynchronizationActive()){r.run();return;}TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization(){@Override public void afterCommit(){r.run();}});}}